VALUES (
  (SELECT id FROM public.programs WHERE slug = 'sleep_disorder_reset' LIMIT 1),
  'sleep_disorder_reset',
  3,
  'Stabilizing Night Sleep',
  'Day 3 - Stabilizing Night Sleep',
  14,
  '[{"type":"intro","dayNumber":3,"dayTitle":"Stabilizing Night Sleep","goal":"Complete Day 3 with steady, consistent action.","estimatedMinutes":14},{"type":"lesson","title":"Today''s Focus","paragraphs":["Complete Day 3 with steady, consistent action."],"highlight":"Consistency compounds into long-term change."},{"type":"exercise_routine","title":"Morning Sunlight Exposure (10–20 Minutes)","exercises":[{"name":"Within 30 Minutes Of Waking, Go Outside And Expose Your Eyes To Natural Daylight.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Step Outside Your Home, Balcony, Or Street.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Do Not Wear Sunglasses.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Face The Direction Of The Sky (not Directly At The Sun).","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Stay Outside For 10–20 Minutes.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Try To Walk Slowly While Getting Sunlight. Movement Strengthens The Signal To Your Body Clock.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Why This Works","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Morning Sunlight Resets The Brain’s Circadian Rhythm, Helping The Body Release Melatonin Naturally","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"At Night.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Without This Signal, Sleep Timing Becomes Irregular.","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This lowers stress hormones and helps your body shift into a calm state.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Morning Movement Increases Sleep Pressure, Which Helps You Feel Naturally Sleepy Later At Night.","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":1,"title":"Caffeine Control Rule","instructions":["Follow this rule strictly:","No caffeine after 2 PM","This includes:","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain in the body 6–8 hours and delay sleep onset."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","Why this works","After the shower, your body temperature drops slightly.","This drop triggers the brain to start producing melatonin, making you feel sleepy."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet forest under a clear night sky.","The air is cool and peaceful.","Everything around you is still.","Focus on this scene while breathing slowly.","Day 3 Sleep Trick – The Reverse Blinking Technique","This trick helps people who try too hard to fall asleep.","When lying in bed:","Close your eyes.","Open them gently for 1–2 seconds.","Close them again.","Repeat this 5–10 times slowly.","Why this works","Trying to sleep often creates performance pressure, which keeps the brain alert.","Reverse blinking removes that pressure and relaxes the brain, making sleep happen naturally.","Day 3 Goal","Reduce the effort and pressure around sleep, allowing the body to fall asleep more naturally.","By Day 3, many people begin noticing:","falling asleep faster","less racing thoughts","deeper relaxation before sleep"],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"journal","prompt":"What helped you most on Day 3?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 3 is complete.","secondaryMessage":"You reinforced stabilizing night sleep today."}]'::jsonb
)
