  'sleep_disorder_reset',
  5,
  'Improving Deep Sleep Quality',
  'Day 5 - Improving Deep Sleep Quality',
  15,
  '[{"type":"intro","dayNumber":5,"dayTitle":"Improving Deep Sleep Quality","goal":"Complete Day 5 with steady, consistent action.","estimatedMinutes":15},{"type":"lesson","title":"Today''s Focus","paragraphs":["Complete Day 5 with steady, consistent action."],"highlight":"Consistency compounds into long-term change."},{"type":"exercise_routine","title":"Morning Sunlight Exposure (10–20 Minutes)","exercises":[{"name":"Within 30 Minutes Of Waking, Go Outside And Expose Your Eyes To Natural Daylight.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Step Outside Your Home, Balcony, Or Street.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Do Not Wear Sunglasses.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Face The Direction Of The Sky (not Directly At The Sun).","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Stay Outside For 10–20 Minutes.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Combine Sunlight Exposure With A Short Walk To Strengthen The Signal To Your Body Clock.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Why This Works","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Morning Sunlight Resets The Brain’s Circadian Rhythm, Helping The Body Release Melatonin Naturally","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"At Night.","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This helps lower stress hormones and relax the nervous system.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Morning Movement Increases Sleep Pressure, Which Helps Your Body Fall Asleep Naturally At Night.","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":1,"title":"Caffeine Control Rule","instructions":["Follow this rule strictly:","No caffeine after 2 PM","This includes:","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours, affecting deep sleep cycles."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","Why this works","After the shower, your body temperature drops slightly.","This temperature drop signals the brain to prepare for sleep and melatonin release."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet cabin during gentle rain.","You can hear the soft sound of rain on the roof.","Everything around you feels calm and safe.","Focus on the sound and scene while breathing slowly.","Day 5 Sleep Trick – The “Feet Warmth Trick”","Cold feet can actually make it harder for the body to fall asleep.","Before going to bed:","wear light socks","or","place a warm blanket over your feet","Why this works","Warming the feet helps blood vessels expand, which allows heat to leave the body.","This helps the body lower its core temperature, which naturally triggers sleep.","Many sleep studies show people fall asleep faster when their feet are warm.","Day 5 Goal","Improve deep sleep quality and physical relaxation so the body can enter deeper restorative sleep","cycles.","By Day 5 some people begin noticing:","falling asleep faster","deeper sleep","feeling more refreshed in the morning"],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"journal","prompt":"What helped you most on Day 5?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 5 is complete.","secondaryMessage":"You reinforced improving deep sleep quality today."}]'::jsonb
)
