INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'sleep_disorder_reset' LIMIT 1),
  'sleep_disorder_reset',
  17,
  'Deep Nervous System Recovery',
  'Day 17 - Deep Nervous System Recovery',
  21,
  '[{"type":"intro","dayNumber":17,"dayTitle":"Deep Nervous System Recovery","goal":"Complete Day 17 with steady, consistent action.","estimatedMinutes":21},{"type":"lesson","title":"Today''s Focus","paragraphs":["Complete Day 17 with steady, consistent action."],"highlight":"Consistency compounds into long-term change."},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Try to combine sunlight with 10 minutes of walking.","Why this works","Morning sunlight resets the brain’s circadian rhythm, which controls melatonin release at night."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This lowers stress hormones and calms the nervous system.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Increased Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Total Movement Time: 40–45 Minutes","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Exercise Routine","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"22–25 Minutes Continuous Walking.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"25 Reps × 5 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"20 Reps × 5 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Jumping Jacks","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"50 Reps × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Plank Hold","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"45 Seconds × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Follow this rule strictly:","No caffeine after 2 PM","This includes:","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours, interfering with sleep cycles."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","Why this works","After the shower, the body temperature naturally drops, signaling the brain that it is time to sleep."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet forest clearing under the moonlight.","The air is cool and peaceful.","Everything around you is calm and silent.","Focus on the calm scene while breathing slowly.","Day 17 Sleep Trick – The “Foot Massage Relaxation”","The feet contain many nerve endings connected to the nervous system.","Relaxing them before bed can help the entire body relax.","Before sleeping:","Sit comfortably on the bed.","Gently massage the bottom of each foot.","Apply light pressure using your thumbs.","Massage for 2–3 minutes per foot.","Why this works","Foot massage stimulates relaxation pathways in the nervous system, reducing physical tension and","helping the body transition into sleep.","Day 17 Goal","Encourage deep physical relaxation and nervous system calm, helping the body enter deeper","restorative sleep cycles.","By Day 17 many people notice:","deeper sleep","fewer awakenings during the night","waking up feeling more refreshed"],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"journal","prompt":"What helped you most on Day 17?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 17 is complete.","secondaryMessage":"You reinforced deep nervous system recovery today."}]'::jsonb
)
